void 
kernel_gpu_opencl_wrapper(	params_common common,
							int* endoRow,
							int* endoCol,
							int* tEndoRowLoc,
							int* tEndoColLoc,
							int* epiRow,
							int* epiCol,
							int* tEpiRowLoc,
							int* tEpiColLoc,
							avi_t* frames)
{
	int i;
	int frame_no;
	fp* frame;

	printf("WG size of kernel = %d \n", NUMBER_THREADS);

	printf("tSize is %d, sSize is %d\n", common.tSize, common.sSize);
	common.in_rows = common.tSize + 1 + common.tSize;
	common.in_cols = common.in_rows;
	common.in_elem = common.in_rows * common.in_cols;
	common.in_mem = sizeof(fp) * common.in_elem;

	common.in2_rows = common.sSize + 1 + common.sSize;
	common.in2_cols = common.in2_rows;
	common.in2_elem = common.in2_rows * common.in2_cols;
	common.in2_mem = sizeof(fp) * common.in2_elem;

	common.conv_rows = common.in_rows + common.in2_rows - 1;												
	common.conv_cols = common.in_cols + common.in2_cols - 1;												
	common.conv_elem = common.conv_rows * common.conv_cols;													
	common.conv_mem = sizeof(fp) * common.conv_elem;
	common.ioffset = 0;
	common.joffset = 0;

	common.in2_pad_add_rows = common.in_rows;
	common.in2_pad_add_cols = common.in_cols;

	common.in2_pad_cumv_rows = common.in2_rows + 2*common.in2_pad_add_rows;
	common.in2_pad_cumv_cols = common.in2_cols + 2*common.in2_pad_add_cols;
	common.in2_pad_cumv_elem = common.in2_pad_cumv_rows * common.in2_pad_cumv_cols;
	common.in2_pad_cumv_mem = sizeof(fp) * common.in2_pad_cumv_elem;

	common.in2_pad_cumv_sel_rowlow = 1 + common.in_rows;													
	common.in2_pad_cumv_sel_rowhig = common.in2_pad_cumv_rows - 1;
	common.in2_pad_cumv_sel_collow = 1;
	common.in2_pad_cumv_sel_colhig = common.in2_pad_cumv_cols;
	common.in2_pad_cumv_sel_rows = common.in2_pad_cumv_sel_rowhig - common.in2_pad_cumv_sel_rowlow + 1;
	common.in2_pad_cumv_sel_cols = common.in2_pad_cumv_sel_colhig - common.in2_pad_cumv_sel_collow + 1;
	common.in2_pad_cumv_sel_elem = common.in2_pad_cumv_sel_rows * common.in2_pad_cumv_sel_cols;
	common.in2_pad_cumv_sel_mem = sizeof(fp) * common.in2_pad_cumv_sel_elem;

	common.in2_pad_cumv_sel2_rowlow = 1;
	common.in2_pad_cumv_sel2_rowhig = common.in2_pad_cumv_rows - common.in_rows - 1;
	common.in2_pad_cumv_sel2_collow = 1;
	common.in2_pad_cumv_sel2_colhig = common.in2_pad_cumv_cols;
	common.in2_sub_cumh_rows = common.in2_pad_cumv_sel2_rowhig - common.in2_pad_cumv_sel2_rowlow + 1;
	common.in2_sub_cumh_cols = common.in2_pad_cumv_sel2_colhig - common.in2_pad_cumv_sel2_collow + 1;
	common.in2_sub_cumh_elem = common.in2_sub_cumh_rows * common.in2_sub_cumh_cols;
	common.in2_sub_cumh_mem = sizeof(fp) * common.in2_sub_cumh_elem;

	common.in2_sub_cumh_sel_rowlow = 1;
	common.in2_sub_cumh_sel_rowhig = common.in2_sub_cumh_rows;
	common.in2_sub_cumh_sel_collow = 1 + common.in_cols;
	common.in2_sub_cumh_sel_colhig = common.in2_sub_cumh_cols - 1;
	common.in2_sub_cumh_sel_rows = common.in2_sub_cumh_sel_rowhig - common.in2_sub_cumh_sel_rowlow + 1;
	common.in2_sub_cumh_sel_cols = common.in2_sub_cumh_sel_colhig - common.in2_sub_cumh_sel_collow + 1;
	common.in2_sub_cumh_sel_elem = common.in2_sub_cumh_sel_rows * common.in2_sub_cumh_sel_cols;
	common.in2_sub_cumh_sel_mem = sizeof(fp) * common.in2_sub_cumh_sel_elem;

	common.in2_sub_cumh_sel2_rowlow = 1;
	common.in2_sub_cumh_sel2_rowhig = common.in2_sub_cumh_rows;
	common.in2_sub_cumh_sel2_collow = 1;
	common.in2_sub_cumh_sel2_colhig = common.in2_sub_cumh_cols - common.in_cols - 1;
	common.in2_sub2_rows = common.in2_sub_cumh_sel2_rowhig - common.in2_sub_cumh_sel2_rowlow + 1;
	common.in2_sub2_cols = common.in2_sub_cumh_sel2_colhig - common.in2_sub_cumh_sel2_collow + 1;
	common.in2_sub2_elem = common.in2_sub2_rows * common.in2_sub2_cols;
	common.in2_sub2_mem = sizeof(fp) * common.in2_sub2_elem;

	common.in2_sqr_rows = common.in2_rows;
	common.in2_sqr_cols = common.in2_cols;
	common.in2_sqr_elem = common.in2_elem;
	common.in2_sqr_mem = common.in2_mem;

	common.in2_sqr_sub2_rows = common.in2_sub2_rows;
	common.in2_sqr_sub2_cols = common.in2_sub2_cols;
	common.in2_sqr_sub2_elem = common.in2_sub2_elem;
	common.in2_sqr_sub2_mem = common.in2_sub2_mem;

	common.in_sqr_rows = common.in_rows;
	common.in_sqr_cols = common.in_cols;
	common.in_sqr_elem = common.in_elem;
	common.in_sqr_mem = common.in_mem;

	common.tMask_rows = common.in_rows + (common.sSize+1+common.sSize) - 1;
	common.tMask_cols = common.tMask_rows;
	common.tMask_elem = common.tMask_rows * common.tMask_cols;
	common.tMask_mem = sizeof(fp) * common.tMask_elem;

	common.mask_rows = common.maxMove;
	common.mask_cols = common.mask_rows;
	common.mask_elem = common.mask_rows * common.mask_cols;
	common.mask_mem = sizeof(fp) * common.mask_elem;

	common.mask_conv_rows = common.tMask_rows;												
	common.mask_conv_cols = common.tMask_cols;												
	common.mask_conv_elem = common.mask_conv_rows * common.mask_conv_cols;												
	common.mask_conv_mem = sizeof(fp) * common.mask_conv_elem;
	common.mask_conv_ioffset = (common.mask_rows-1)/2;
	if(0.5 < (common.mask_rows-1) % 2){
		common.mask_conv_ioffset = common.mask_conv_ioffset + 1;
	}
	common.mask_conv_joffset = (common.mask_cols-1)/2;
	if(0.5 < (common.mask_cols-1) % 2){
		common.mask_conv_joffset = common.mask_conv_joffset + 1;
	}

	printf("frame progress: ");
	fflush(NULL);

	for(frame_no=0; common.frames_processed > frame_no; frame_no++){

		frame = get_frame(	frames,								
							frame_no,							
							0,									
							0,									
							1);									

		fp* d_frame = frame;
		fp* d_endoT = (fp*)malloc(sizeof(fp) * common.in_elem * common.endoPoints);
		fp* d_epiT = (fp*)malloc(sizeof(fp) * common.in_elem * common.epiPoints);
		fp* d_in2_all = (fp*)malloc(sizeof(fp) * common.in2_elem * common.allPoints);
		fp* d_conv_all = (fp*)malloc(sizeof(fp) * common.conv_elem * common.allPoints);
		fp* d_in2_pad_cumv_all = (fp*)malloc(sizeof(fp) * common.in2_pad_cumv_elem * common.allPoints);
		fp* d_in2_pad_cumv_sel_all = (fp*)malloc(sizeof(fp) * common.in2_pad_cumv_sel_elem * common.allPoints);
		fp* d_in2_sub_cumh_all = (fp*)malloc(sizeof(fp) * common.in2_sub_cumh_elem * common.allPoints);
		fp* d_in2_sub_cumh_sel_all = (fp*)malloc(sizeof(fp) * common.in2_sub_cumh_sel_elem * common.allPoints);
		fp* d_in2_sub2_all = (fp*)malloc(sizeof(fp) * common.in2_sub2_elem * common.allPoints);
		fp* d_in2_sqr_all = (fp*)malloc(sizeof(fp) * common.in2_sqr_elem * common.allPoints);
		fp* d_in2_sqr_sub2_all = (fp*)malloc(sizeof(fp) * common.in2_sqr_sub2_elem * common.allPoints);
		fp* d_in_sqr_all = (fp*)malloc(sizeof(fp) * common.in_sqr_elem * common.allPoints);
		fp* d_tMask_all = (fp*)malloc(sizeof(fp) * common.tMask_elem * common.allPoints);
		fp* d_mask_conv_all = (fp*)malloc(sizeof(fp) * common.mask_conv_elem * common.allPoints);
		fp* d_in_mod_temp_all = (fp*)malloc(sizeof(fp) * common.in_elem * common.allPoints);
		fp* in_partial_sum_all = (fp*)malloc(sizeof(fp) * common.in_cols * common.allPoints);
		fp* in_sqr_partial_sum_all = (fp*)malloc(sizeof(fp) * common.in_sqr_rows * common.allPoints);
		fp* par_max_val_all = (fp*)malloc(sizeof(fp) * common.mask_conv_rows * common.allPoints);
		int* par_max_coo_all = (int*)malloc(sizeof(int) * common.mask_conv_rows * common.allPoints);
		fp* in_final_sum_all = (fp*)malloc(sizeof(fp) * common.allPoints);
		fp* in_sqr_final_sum_all = (fp*)malloc(sizeof(fp) * common.allPoints);
		fp* denomT_all = (fp*)malloc(sizeof(fp) * common.allPoints);
		fp* checksum = (fp*)malloc(sizeof(fp) * CHECK);

#ifdef TEST_CHECKSUM
		for(i=0; i<CHECK; i++){
			checksum[i] = 0;
		}
#endif

#pragma omp parallel num_threads(common.allPoints)
		{
			int bx = omp_get_thread_num();
			int tx = 0; 
			int ei_new;
			int rot_row, rot_col, in2_rowlow, in2_collow, ic, jc, jp1, ja1, ja2, ip1, ia1, ia2, ja, jb, ia, ib;
			fp s, sum, temp, temp2, mean, mean_sqr, variance, deviation, largest_value_current, largest_value, fin_max_val;
			int i, j, row, col, ori_row, ori_col, position, pos_ori, location, cent, tMask_row, tMask_col;
			int largest_coordinate_current, largest_coordinate, fin_max_coo, largest_row, largest_col, offset_row, offset_col;
			int pointer, ori_pointer, loc_pointer;
			fp largest_value_current_local = 0;
			fp largest_value_local = 0;
			int largest_coordinate_current_local = 0;
			int largest_coordinate_local = 0;
			fp fin_max_val_local = 0;
			int fin_max_coo_local = 0;

			int d_unique_point_no;
			int* d_unique_d_Row;
			int* d_unique_d_Col;
			int* d_unique_d_tRowLoc;
			int* d_unique_d_tColLoc;
			fp* d_in;
			if(common.endoPoints > bx){
				d_unique_point_no = bx;													
				d_unique_d_Row = endoRow;												
				d_unique_d_Col = endoCol;												
				d_unique_d_tRowLoc = tEndoRowLoc;										
				d_unique_d_tColLoc = tEndoColLoc;										
				d_in = &d_endoT[d_unique_point_no * common.in_elem];					
			}
			else{
				d_unique_point_no = bx-common.endoPoints;								
				d_unique_d_Row = epiRow;												
				d_unique_d_Col = epiCol;												
				d_unique_d_tRowLoc = tEpiRowLoc;										
				d_unique_d_tColLoc = tEpiColLoc;										
				d_in = &d_epiT[d_unique_point_no * common.in_elem];					
			}

			fp* d_unique_d_in2 = &d_in2_all[bx*common.in2_elem];
			fp* d_unique_d_conv = &d_conv_all[bx*common.conv_elem];
			fp* d_unique_d_in2_pad_cumv = &d_in2_pad_cumv_all[bx*common.in2_pad_cumv_elem];
			fp* d_unique_d_in2_pad_cumv_sel = &d_in2_pad_cumv_sel_all[bx*common.in2_pad_cumv_sel_elem];
			fp* d_unique_d_in2_sub_cumh = &d_in2_sub_cumh_all[bx*common.in2_sub_cumh_elem];
			fp* d_unique_d_in2_sub_cumh_sel = &d_in2_sub_cumh_sel_all[bx*common.in2_sub_cumh_sel_elem];
			fp* d_unique_d_in2_sub2 = &d_in2_sub2_all[bx*common.in2_sub2_elem];
			fp* d_unique_d_in2_sqr = &d_in2_sqr_all[bx*common.in2_sqr_elem];
			fp* d_unique_d_in2_sqr_sub2 = &d_in2_sqr_sub2_all[bx*common.in2_sqr_sub2_elem];
			fp* d_unique_d_in_sqr = &d_in_sqr_all[bx*common.in_sqr_elem];
			fp* d_unique_d_tMask = &d_tMask_all[bx*common.tMask_elem];
			fp* d_unique_d_mask_conv = &d_mask_conv_all[bx*common.mask_conv_elem];

			fp* d_in_mod_temp = &d_in_mod_temp_all[bx*common.in_elem];
			fp* in_partial_sum = &in_partial_sum_all[bx*common.in_cols];
			fp* in_sqr_partial_sum = &in_sqr_partial_sum_all[bx*common.in_sqr_rows];
			fp* par_max_val = &par_max_val_all[bx*common.mask_conv_rows];
			int* par_max_coo = &par_max_coo_all[bx*common.mask_conv_rows];

			fp* in_final_sum = &in_final_sum_all[bx];
			fp* in_sqr_final_sum = &in_sqr_final_sum_all[bx];
			fp* denomT = &denomT_all[bx];

			if(frame_no == 0){
#ifdef INIT
				for(i=0; i<common.no_frames; i++){
					d_unique_d_tRowLoc[d_unique_point_no*common.no_frames+i] = 0;
					d_unique_d_tColLoc[d_unique_point_no*common.no_frames+i] = 0;
				}
				for(i=0; i<common.in_elem; i++){
					d_in[i] = 0;
				}
#endif

				pointer = d_unique_point_no*common.no_frames+frame_no;
				d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no];
				d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no];

				for(ei_new = 0; ei_new < common.in_elem; ei_new++){
					row = (ei_new+1) % common.in_rows - 1;												
					col = (ei_new+1) / common.in_rows + 1 - 1;											
					if(0 == (ei_new+1) % common.in_rows){
						row = common.in_rows - 1;
						col -= 1;
					}

					ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
					ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
					ori_pointer = ori_col*common.frame_rows+ori_row;

					d_in[col*common.in_rows+row] = d_frame[ori_pointer];
				}

#ifdef TEST_CHECKSUM
				sum = 0;
				for(i=0; i<common.in_elem; i++){
					sum += d_in[i];
				}
				if(bx==0) checksum[0] = sum;
#endif
			}

			if(frame_no != 0){
#ifdef INIT
				for(i=0; i<common.in2_elem; i++) d_unique_d_in2[i] = 0;
				for(i=0; i<common.conv_elem; i++) d_unique_d_conv[i] = 0;
				for(i=0; i<common.in2_pad_cumv_elem; i++) d_unique_d_in2_pad_cumv[i] = 0;
				for(i=0; i<common.in2_pad_cumv_sel_elem; i++) d_unique_d_in2_pad_cumv_sel[i] = 0;
				for(i=0; i<common.in2_sub_cumh_elem; i++) d_unique_d_in2_sub_cumh[i] = 0;
				for(i=0; i<common.in2_sub_cumh_sel_elem; i++) d_unique_d_in2_sub_cumh_sel[i] = 0;
				for(i=0; i<common.in2_sub2_elem; i++) d_unique_d_in2_sub2[i] = 0;
				for(i=0; i<common.in2_sqr_elem; i++) d_unique_d_in2_sqr[i] = 0;
				for(i=0; i<common.in2_sqr_sub2_elem; i++) d_unique_d_in2_sqr_sub2[i] = 0;
				for(i=0; i<common.in_sqr_elem; i++) d_unique_d_in_sqr[i] = 0;
				for(i=0; i<common.tMask_elem; i++) d_unique_d_tMask[i] = 0;
				for(i=0; i<common.mask_conv_elem; i++) d_unique_d_mask_conv[i] = 0;
				for(i=0; i<common.in_elem; i++) d_in_mod_temp[i] = 0;
				for(i=0; i<common.in_cols; i++) in_partial_sum[i] = 0;
				for(i=0; i<common.in_sqr_rows; i++) in_sqr_partial_sum[i] = 0;
				for(i=0; i<common.mask_conv_rows; i++) par_max_val[i] = 0;
				for(i=0; i<common.mask_conv_rows; i++) par_max_coo[i] = 0;
				in_final_sum[0] = 0;
				in_sqr_final_sum[0] = 0;
				denomT[0] = 0;
#endif

				in2_rowlow = d_unique_d_Row[d_unique_point_no] - common.sSize;													
				in2_collow = d_unique_d_Col[d_unique_point_no] - common.sSize;

				for(ei_new = 0; ei_new < common.in2_elem; ei_new++){
					row = (ei_new+1) % common.in2_rows - 1;												
					col = (ei_new+1) / common.in2_rows + 1 - 1;											
					if(0 == (ei_new+1) % common.in2_rows){
						row = common.in2_rows - 1;
						col -= 1;
					}

					ori_row = row + in2_rowlow - 1;
					ori_col = col + in2_collow - 1;
					d_unique_d_in2[ei_new] = d_frame[ori_col*common.frame_rows+ori_row];
				}

#ifdef TEST_CHECKSUM
				sum = 0;
				for(i=0; i<common.in2_elem; i++) sum += d_unique_d_in2[i];
				if(bx==0) checksum[1] = sum;
#endif

				for(ei_new = 0; ei_new < common.in_elem; ei_new++){
					row = (ei_new+1) % common.in_rows - 1;												
					col = (ei_new+1) / common.in_rows + 1 - 1;											
					if(0 == (ei_new+1) % common.in_rows){
						row = common.in_rows - 1;
						col -= 1;
					}

					rot_row = (common.in_rows-1) - row;
					rot_col = (common.in_rows-1) - col;
					d_in_mod_temp[ei_new] = d_in[rot_col*common.in_rows+rot_row];
				}

#ifdef TEST_CHECKSUM
				sum = 0;
				for(i=0; i<common.in_elem; i++) sum += d_in_mod_temp[i];
				if(bx==0) checksum[2] = sum;
#endif

				for(ei_new = 0; ei_new < common.conv_elem; ei_new++){
					ic = (ei_new+1) % common.conv_rows;												
					jc = (ei_new+1) / common.conv_rows + 1;											
					if(0 == (ei_new+1) % common.conv_rows){
						ic = common.conv_rows;
						jc -= 1;
					}

					j = jc + common.joffset;
					jp1 = j + 1;
					if(jp1 > common.in2_cols){
						ja1 = jp1 - common.in2_cols;
					}
					else{
						ja1 = 1;
					}
					if(j > common.in_cols){
						ja2 = common.in_cols;
					}
					else{
						ja2 = j;
					}

					i = ic + common.ioffset;
					ip1 = i + 1;

					if(ip1 > common.in2_rows){
						ia1 = ip1 - common.in2_rows;
					}
					else{
						ia1 = 1;
					}
					if(i > common.in_rows){
						ia2 = common.in_rows;
					}
					else{
						ia2 = i;
					}

					s = 0;

					for(ja=ja1; ja2 >= ja; ja++){
						jb = jp1 - ja;
						for(ia=ia1; ia2 >= ia; ia++){
							ib = ip1 - ia;
							s = s + d_in_mod_temp[common.in_rows*(ja-1)+ia-1] * d_unique_d_in2[common.in2_rows*(jb-1)+ib-1];
						}
					}

					d_unique_d_conv[ei_new] = s;
				}

#ifdef TEST_CHECKSUM
				sum = 0;
				for(i=0; i<common.conv_elem; i++) sum += d_unique_d_conv[i];
				if(bx==0) checksum[3] = sum;
#endif

				for(ei_new = 0; ei_new < common.in2_pad_cumv_elem; ei_new++){
					row = (ei_new+1) % common.in2_pad_cumv_rows - 1;												
					col = (ei_new+1) / common.in2_pad_cumv_rows + 1 - 1;											
					if(0 == (ei_new+1) % common.in2_pad_cumv_rows){
						row = common.in2_pad_cumv_rows - 1;
						col -= 1;
					}

					if(	(common.in2_pad_add_rows-1) < row &&														
						(common.in2_pad_add_rows+common.in2_rows) > row && 
						(common.in2_pad_add_cols-1) < col && 
						(common.in2_pad_add_cols+common.in2_cols) > col){
						ori_row = row - common.in2_pad_add_rows;
						ori_col = col - common.in2_pad_add_cols;
						d_unique_d_in2_pad_cumv[ei_new] = d_unique_d_in2[ori_col*common.in2_rows+ori_row];
					}
					else{																			
						d_unique_d_in2_pad_cumv[ei_new] = 0;
					}
				}

#ifdef TEST_CHECKSUM
				sum = 0;
				for(i=0; i<common.in2_pad_cumv_elem; i++) sum += d_unique_d_in2_pad_cumv[i];
				if(bx==0) checksum[4] = sum;
#endif

				for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++){
					pos_ori = ei_new*common.in2_pad_cumv_rows;
					sum = 0;
					for(position = pos_ori; pos_ori+common.in2_pad_cumv_rows > position; position += 1){
						d_unique_d_in2_pad_cumv[position] = d_unique_d_in2_pad_cumv[position] + sum;
						sum = d_unique_d_in2_pad_cumv[position];
					}
				}

