				largest_row = (fin_max_coo_local+1) % common.mask_conv_rows - 1;											
				largest_col = (fin_max_coo_local+1) / common.mask_conv_rows;												
				if(0 == (fin_max_coo_local+1) % common.mask_conv_rows){
					largest_row = common.mask_conv_rows - 1;
					largest_col -= 1;
				}

				largest_row += 1;																	
				largest_col += 1;																	
				offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
				offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
				pointer = d_unique_point_no*common.no_frames+frame_no;
				d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no] + offset_row;
				d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no] + offset_col;

#ifdef TEST_CHECKSUM
				if(bx==0) checksum[35] = checksum[35]+d_unique_d_tRowLoc[pointer]+d_unique_d_tColLoc[pointer];
#endif
			}

			if(frame_no != 0 && (frame_no)%10 == 0){
#ifdef INIT
				for(i=0; i<common.in_elem; i++){
					d_in[i] = 0;
				}
#endif

				loc_pointer = d_unique_point_no*common.no_frames+frame_no;
				d_unique_d_Row[d_unique_point_no] = d_unique_d_tRowLoc[loc_pointer];
				d_unique_d_Col[d_unique_point_no] = d_unique_d_tColLoc[loc_pointer];

				for(ei_new = 0; ei_new < common.in_elem; ei_new++){
					row = (ei_new+1) % common.in_rows - 1;												
					col = (ei_new+1) / common.in_rows + 1 - 1;											
					if(0 == (ei_new+1) % common.in_rows){
						row = common.in_rows - 1;
						col -= 1;
					}

					ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
					ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
					ori_pointer = ori_col*common.frame_rows+ori_row;

					d_in[ei_new] = common.alpha*d_in[ei_new] + (1-common.alpha)*d_frame[ori_pointer];
				}

#ifdef TEST_CHECKSUM
				sum = 0;
				for(i=0; i<common.in_elem; i++) sum += d_in[i];
				if(bx==0) checksum[36] = sum;
#endif
			}
		}

		free(frame);

		printf("%d ", frame_no);
		fflush(NULL);

#ifdef TEST_CHECKSUM
		printf("CHECKSUM:\n");
		for(i=0; i<CHECK; i++){
				printf("%f ", checksum[i]);
		}
		printf("\n\n");
#endif

		free(d_endoT);
		free(d_epiT);
		free(d_in2_all);
		free(d_conv_all);
		free(d_in2_pad_cumv_all);
		free(d_in2_pad_cumv_sel_all);
		free(d_in2_sub_cumh_all);
		free(d_in2_sub_cumh_sel_all);
		free(d_in2_sub2_all);
		free(d_in2_sqr_all);
		free(d_in2_sqr_sub2_all);
		free(d_in_sqr_all);
		free(d_tMask_all);
		free(d_mask_conv_all);
		free(d_in_mod_temp_all);
		free(in_partial_sum_all);
		free(in_sqr_partial_sum_all);
		free(par_max_val_all);
		free(par_max_coo_all);
		free(in_final_sum_all);
		free(in_sqr_final_sum_all);
		free(denomT_all);
		free(checksum);
	}

	printf("\n");
	fflush(NULL);

#ifdef TEST_OUTPUT
	for(i=0; i<common.frames_processed; i++){
		printf("%d: ", i);
		for(j=0; j<common.endoPoints; j++){
			printf("%d ", tEndoRowLoc[j*common.no_frames+i]);
		}
		printf("\n\n");
	}
#endif
}

int platform_id_inuse = 0; 
int device_id_inuse = 0; 

int
main(	int argc, 
		char* argv []){

    printf("WG size of kernel = %d \n", NUMBER_THREADS);

	params_common common;
	common.common_mem = sizeof(params_common);

	char* video_file_name = NULL;
	char* input_file_name = NULL;
    common.frames_processed = -1;

    for (int i=0; argc > i; ++i) {
        switch (argv[i][1]) {
        case 'f':	
            if (++i < argc) {
                video_file_name = argv[i];
            } else {
                printf("Could not read argument after option %s\n", argv[i-1]);
                return 1;
            }
            break;
        case 'i':	 
            if (++i < argc) {
                input_file_name = argv[i];
            } else {
                printf("Could not read argument after option %s\n", argv[i-1]);
                return 1;
            }
            break;
        case 'h':
		    printf("%s <-f video_file> <-i input_file> <-n num_frames> [-p platform_id] [-n device_id]\n", argv[0]);
            return 0;
        case 'n':   
            if (++i < argc) {
    		    common.frames_processed = atoi(argv[i]);
            } else {
                printf("Could not read argument after option %s\n", argv[i-1]);
                return 1;
            }
            break;
        case 'p':   
            if (++i < argc) {
                platform_id_inuse = atoi(argv[i]);
            } else {
                printf("Could not read argument after option %s\n", argv[i-1]);
                return 1;
            }
            break;
        case 'd':   
            if (++i < argc) {
                device_id_inuse = atoi(argv[i]);
            } else {
                printf("Could not read argument after option %s\n", argv[i-1]);
                return 1;
            }
            break;
        }
    }

    if (NULL == input_file_name || NULL == video_file_name) {
        printf("Input or video file name is missing\n");
        return 0;
    }

	int i;
	avi_t* frames;

	frames = (avi_t*)AVI_open_input_file(video_file_name, 1);														
	if (NULL == frames)  {
		   AVI_print_error((char *) "Error with AVI_open_input_file");
		   return -1;
	}

	common.no_frames = AVI_video_frames(frames);
	common.frame_rows = AVI_video_height(frames);
	common.frame_cols = AVI_video_width(frames);
	common.frame_elem = common.frame_rows * common.frame_cols;
	common.frame_mem = sizeof(fp) * common.frame_elem;

    if (0 > common.frames_processed || common.no_frames < common.frames_processed){
        printf("ERROR: %d is an incorrect number of frames specified, select in the range of 0-%d\n", common.frames_processed, common.no_frames);
        return 0;
    }

	read_parameters(	input_file_name,
						&common.tSize,
						&common.sSize,
						&common.maxMove,
						&common.alpha);

	read_header(	input_file_name,
					&common.endoPoints,
					&common.epiPoints);

	common.allPoints = common.endoPoints + common.epiPoints;

	common.endo_mem = sizeof(int) * common.endoPoints;

	int* endoRow;
	endoRow = (int*)malloc(common.endo_mem);
	int* endoCol;
	endoCol = (int*)malloc(common.endo_mem);
	int* tEndoRowLoc;
	tEndoRowLoc = (int*)malloc(common.endo_mem * common.no_frames);
	int* tEndoColLoc;
	tEndoColLoc = (int*)malloc(common.endo_mem * common.no_frames);

	common.epi_mem = sizeof(int) * common.epiPoints;

	int* epiRow;
	epiRow = (int *)malloc(common.epi_mem);
	int* epiCol;
	epiCol = (int *)malloc(common.epi_mem);
	int* tEpiRowLoc;
	tEpiRowLoc = (int *)malloc(common.epi_mem * common.no_frames);
	int* tEpiColLoc;
	tEpiColLoc = (int *)malloc(common.epi_mem * common.no_frames);

	read_data(	input_file_name,
				common.endoPoints,
				endoRow,
				endoCol,
				common.epiPoints,
				epiRow,
				epiCol);

	kernel_gpu_opencl_wrapper(	common,
								endoRow,
								endoCol,
								tEndoRowLoc,
								tEndoColLoc,
								epiRow,
								epiCol,
								tEpiRowLoc,
								tEpiColLoc,
								frames);

#ifdef OUTPUT
	write_data(	"result.txt",
			common.no_frames,
			common.frames_processed,		
				common.endoPoints,
				tEndoRowLoc,
				tEndoColLoc,
				common.epiPoints,
				tEpiRowLoc,
				tEpiColLoc);
#endif

	free(endoRow);
	free(endoCol);
	free(tEndoRowLoc);
	free(tEndoColLoc);

	free(epiRow);
	free(epiCol);
	free(tEpiRowLoc);
	free(tEpiColLoc);

	AVI_close(frames);

	return 0;
}
